import config from '~/config'
export default {
  components: {},
  props: {
    limit: {
      type: Number,
      default: 1
    },
    isSlot: {
      type: Boolean,
      default: false
    },
    autoUpload: {
      type: Boolean,
      default: true
    },
    onChange: {
      type: Function,
      default: () => {}
    }
  },
  watch: {},
  data() {
    return {
      url: config.baseUrl
    };
  },
  created() {},
  computed: {},
  methods: {
    success(res, file, fileList) {
      if(!this.autoUpload) {
        return
      }
      this.$message({
        message: "上传成功",
        type: 'success'
      })
      this.$emit('success', fileList)
    },
    error(res) {
      this.$message({
        message: "上传失败，请重新上传",
        type: 'error'
      })
    },

    beforeAvatarUpload(file) {
      var testmsg = file.name.substring(file.name.lastIndexOf('.') + 1)
      console.log('fdsadsf')
      const extension = testmsg === 'jpg'
      const extension2 = testmsg === 'png'
      const extension4 = testmsg === 'jpeg'
      if (!extension && !extension2) {
        this.$message({
          message: '上传文件只能是 jpg, jpeg, png格式!',
          type: 'warning'
        })
        return false
      }
      return extension || extension2 || extension4
    }
  },
};
