import Upload from "~/components/public/upload";
export default {
  head() {
    return {
      title: this.$store.getters.headTitle,
      link: [
        {
          rel: "icon",
          type: "image/x-icon",
          href: this.$store.getters.favicon,
        },
      ],
    };
  },
  async asyncData({ $get, query }) {
    const id = query.id;
    let { data } = await $get("goods_comment/getGoods", {
      params: { id },
    });
    return {
      goodsInfo: data,
      id,
    };
  },
  layout: "user_lauout",
  components: {
    Upload,
  },
  data() {
    return {
      goodsInfo: {},
      goodsRate: 0,
      descRate: 0,
      serverRate: 0,
      deliveryRate: 0,
      comment: "",
      fileList: [],
      goodsTexts: ["差评", "差评", "中评", "好评", "好评"],
    };
  },
  methods: {
    onSuccess(res) {
      this.fileList = res.map((item) => item.response.data);
    },
    onSubmit() {
      let {
        goodsRate,
        fileList,
        comment,
        deliveryRate,
        descRate,
        serverRate,
      } = this;
      let image = fileList.map((item) => item.url);
      if (!goodsRate)
        return this.$message({
          message: "请对商品进行评分",
          type: "error",
        });
      if (!descRate)
        return this.$message({
          message: "请对描述相符进行评分",
          type: "error",
        });
      if (!serverRate)
        return this.$message({
          message: "请对服务态度进行评分",
          type: "error",
        });
      if (!deliveryRate)
        return this.$message({
          message: "请对配送服务进行评分",
          type: "error",
        });
      this.$post("goods_comment/addGoodsComment", {
        id: parseInt(this.id),
        goods_comment: goodsRate,
        service_comment: serverRate,
        express_comment: deliveryRate,
        description_comment: descRate,
        comment,
        image,
      }).then((res) => {
        if (res.code == 1) {
          this.$message({
            message: "评价成功",
            type: "success",
          });
          setTimeout(() => {
            this.$router.replace({
              path: "/user/evaluation",
              query: {
                type: 2,
              },
            });
          }, 1500);
        }
      });
    },
  },
};
